// Update plot
let lastTime
function update_data(time) {
    lastTime = time

    if (lastTime == null || logData.time == null) {
        return
    }

    const value = linear_interp(logData.value, logData.time, time)
    text.innerHTML = value.toFixed(Math.round(options.decimalPlaces))

