// Varbles to hold data
const logData = {
    log: null,
    time: null,
    value: null
}

// Load function
loadLog = function (newLog) {
    logData.log = newLog
    if (options.logItem == null || logData.log == null) {
        return
    }

    const match = options.logItem.match(/^(\w+)(?:\[(\d+)\])?\.(\w+)$/);
    const name = match[1]
    const instance = match[2]
    const field = match[3]

    let timeUS
    let value

    if (instance != null) {
        const instanceNum = parseInt(instance)
        timeUS = logData.log.get_instance(name, instanceNum, "TimeUS")
        value = logData.log.get_instance(name, instanceNum, field)
    } else {
        timeUS = logData.log.get(name, "TimeUS")
        value = logData.log.get(name, field)
    }

    if (timeUS == null || value == null) {
        throw new Error(`Uknown log message: ${options.logItem}`)
    }

    logData.time = array_scale(timeUS, 1/1000000)
    logData.value = array_scale(value, options.scaleFactor)

    update_data(lastTime)
}

// Runtime function
setTime = function(time) {
    update_data(time)
}

