// Import Gauges from https://github.com/teocci/js-module-flight-indicators
// Add ccs with link tag
const ccs = document.createElement('link')
ccs.rel = "stylesheet"
ccs.href = "https://unpkg.com/flight-indicators-js@1.0.5/css/flight-indicators.css"
document.body.appendChild(ccs)

let attitude
import("https://unpkg.com/flight-indicators-js@1.0.5/esm/module-flight-indicators.mjs").then((mod) => {
    const FlightIndicators = mod.default

    attitude = new FlightIndicators(
        div,
        FlightIndicators.TYPE_ATTITUDE
    )

    // This is a dirty hack to switch to remote copy's of images
    let images = div.querySelectorAll("img")
    for (const image of images) {
        let src = image.src

        var lastIndex = src.lastIndexOf("/img/")
        image.src = "https://unpkg.com/flight-indicators-js@1.0.5" + src.substr(lastIndex)

        // Hide box is broken, hide manually
        // see: https://github.com/teocci/js-module-flight-indicators/pull/1
        if (src.endsWith("fi_box.svg")) {
            image.style.display = "none"
        }
    }

    resize()
})

// Remove margin and border to give more room
div.style.margin = 0
div.style.border = 0
div.style.background = "none"
div.style.padding = 0

// Center gauge
div.style.display = "flex"
div.style.justifyContent = "center"
div.style.alignItems = "center"

function resize() {

    if (attitude == null) {
        return
    }

    // Get width and height of widget
    const width = div.offsetWidth
    const height = div.offsetHeight

    const max_size = Math.min(width, height)
    attitude.resize(max_size)

    setTime(lastTime)
}

// Watch for size changes
new ResizeObserver(() => { resize() }).observe(div)

let logData = {
    time: null,
    roll: null,
    pitch: null,
}

// Load function
loadLog = function (log) {
    const ATT = log.get("ATT")
    logData.time = array_scale(ATT.TimeUS, 1/1000000)
    logData.roll = ATT.Roll
    logData.pitch = ATT.Pitch

    setTime(lastTime)
}

// Runtime function
let lastTime
setTime = function(time) {

    if (time == null) {
        return
    }
    lastTime = time


    if (logData.time == null || logData.roll == null || logData.pitch == null) {
        return
    }

    if (attitude == null) {
        return
    }

    const roll = linear_interp(logData.roll, logData.time, time)
    const pitch = linear_interp(logData.pitch, logData.time, time)

    // Roll is backwards for some reason...
    attitude.updateRoll(-roll)
    attitude.updatePitch(pitch)
}

// Include plotly
const script = document.createElement("script")
script.src = "https://cdn.plot.ly/plotly-2.35.0.min.js"
document.body.appendChild(script)

// Setup layout
const plot_layout = { 
    title: { text: options.title },
    legend: { itemclick: false, itemdoubleclick: false }, 
    margin: { b: 50, l: 65, r: 50, t: 50 },
    xaxis: { title: { text: "time (s)" }, range: [-options.time, options.time], zeroline: false, showline: true, mirror: true },
    yaxis: { title: { text: options.label }, zeroline: false, showline: true, mirror: true }
}

const plot_data = [
    { mode: 'lines', x: [], y:[], line: { color: options.color } }
]

data = {
    time: [],
    value: []
}

let plot_created = false

// Update plot
let lastTime
function update_data(time) {
    lastTime = time

    if (logData.time == null) {
        return
    }

    // Update plot
    plot_data[0].x = array_offset(logData.time, -lastTime)
    plot_data[0].y = logData.value

    // Make sure plotly is loaded
    if (window.Plotly !== undefined) {
        if (!plot_created) {
            replot()
        }
        Plotly.redraw(div)
    }
}


function replot() {
    // Clear plot and redraw to cope with change in size or options
    plot_layout.title.text = options.title
    plot_layout.xaxis.range[0] = -options.time
    plot_layout.yaxis.title.text = options.label
    plot_data[0].line.color = options.color

    if (window.Plotly !== undefined) {
        Plotly.purge(div)
        Plotly.newPlot(div, plot_data, plot_layout, {displaylogo: false})
        plot_created = true
    }
}

// Watch for size changes
new ResizeObserver(() => { replot() }).observe(div)

